import{_ as e,o as l,c as i,a4 as t}from"./chunks/framework.BhEBm8_q.js";const c=JSON.parse('{"title":"소리내어 읽기 (TTS)","description":"","frontmatter":{},"headers":[],"relativePath":"13-tts.md","filePath":"13-tts.md"}'),r={name:"13-tts.md"};function n(s,a,T,o,d,h){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="소리내어-읽기-tts" tabindex="-1">소리내어 읽기 (TTS) <a class="header-anchor" href="#소리내어-읽기-tts" aria-label="Permalink to “소리내어 읽기 (TTS)”">​</a></h1><p><em>EPUB TTS 패널</em></p><p>EPUB은 소리내어 읽기(TTS)를 지원합니다. 눈으로 읽기 어려운 상황에서 본문을 음성으로 들을 수 있습니다.</p><h2 id="사용-방법" tabindex="-1">사용 방법 <a class="header-anchor" href="#사용-방법" aria-label="Permalink to “사용 방법”">​</a></h2><p>EPUB 리더에서 TTS를 켜면 작은 패널이 나타납니다.</p><ul><li>재생 / 일시정지 / 재개 / 정지</li><li>속도, 음높이, 볼륨 조절</li><li>사용할 TTS 엔진과 음성 선택</li></ul><p>재생은 사용자가 직접 시작해야 하며, 읽는 위치가 본문에 함께 표시됩니다. 설정에서 EPUB TTS가 꺼져 있으면 버튼이 비활성화되고 &quot;TTS를 사용할 수 없습니다.&quot;가 표시됩니다.</p><h2 id="백그라운드-재생과-잠금화면-컨트롤" tabindex="-1">백그라운드 재생과 잠금화면 컨트롤 <a class="header-anchor" href="#백그라운드-재생과-잠금화면-컨트롤" aria-label="Permalink to “백그라운드 재생과 잠금화면 컨트롤”">​</a></h2><p>설정에서 백그라운드 재생을 켜면 화면을 잠근 뒤에도 이어 들을 수 있습니다.</p><ul><li>Android: 알림과 잠금화면에서 재생·일시정지·정지</li><li>iOS: 잠금화면과 제어센터에서 재생·일시정지·정지</li><li>잠금화면에는 문서 제목·앱 이름·포맷·재생 상태 같은 최소 정보만 표시됩니다(본문 문장은 표시하지 않음).</li></ul><p>백그라운드 재생이 꺼져 있으면 리더를 벗어나거나 앱이 백그라운드로 가면 멈춥니다.</p><h2 id="지원-범위" tabindex="-1">지원 범위 <a class="header-anchor" href="#지원-범위" aria-label="Permalink to “지원 범위”">​</a></h2><p>현재 TTS는 EPUB만 지원합니다.</p><ul><li>TXT, Markdown, PDF, HWP/HWPX: 진입점을 숨기며 추후 지원 예정</li><li>CBZ/CB7: 이미지 포맷이라 대상이 아님</li></ul><h2 id="개인정보" tabindex="-1">개인정보 <a class="header-anchor" href="#개인정보" aria-label="Permalink to “개인정보”">​</a></h2><p>소리내어 읽기는 읽을 텍스트만 OS 또는 사용자가 선택한 TTS 엔진으로 전달합니다.</p><ul><li>원본 문서 전체나 색인을 외부 서버로 올리지 않습니다.</li><li>기본 OS 엔진이 아닌 외부 엔진을 고르면, 읽을 텍스트가 그 엔진 앱·서비스로 전달될 수 있습니다.</li><li>클라우드 TTS·번역처럼 네트워크로 보내는 기능은 별도이며, 실행 전에 동의를 받습니다.</li></ul>',17)])])}const _=e(r,[["render",n]]);export{c as __pageData,_ as default};
